mapper.insert:
INSERT INTO tasting_note            /* 테이스팅 노트 테이블 */
(
    user_id                         /* 회원 키 */
  , drink_id                        /* 주류 키 */
  , title                           /* 노트 제목 */
  , content                         /* 노트 내용 */
  , rating                          /* 노트 별점 */
  , created_at                      /* 등록 일시 */
)
VALUES
(
    #{userId}
  , #{drinkId}
  , #{title}
  , #{content}
  , #{rating}
  , NOW()
)
